function seedRealSquads(clubs){
  const result=[];
  for(const [clubName,rows] of Object.entries(REAL_SQUADS)){
    const clubId=clubs.find(c=>c.name===clubName)?.id;if(!clubId)continue;
    rows.forEach((row,i)=>{const [name,pos,age,ovr,pot,nation]=row.split('|');result.push(makePlayer(name,clubId,nation||guessNation(name),pos,Number(age),Number(ovr),Number(pot),{number:i+1,scouted:false,isFictional:false,source:'Pemain nyata terkurasi'}));});
  }
  return result;
}
function guessNation(name){
  const map={'M. Fauzan A.F':'Indonesia','Kylian Mbappe':'Prancis','Vinicius Junior':'Brasil','Jude Bellingham':'Inggris','Lamine Yamal':'Spanyol','Mohamed Salah':'Mesir','Erling Haaland':'Norwegia','Harry Kane':'Inggris','Kevin De Bruyne':'Belgia','Luka Modric':'Kroasia','Lautaro Martinez':'Argentina','Dusan Vlahovic':'Serbia','Victor Osimhen':'Nigeria','Jamal Musiala':'Jerman','Michael Olise':'Prancis','Florian Wirtz':'Jerman','Bukayo Saka':'Inggris','Cole Palmer':'Inggris'};
  return map[name]||pick(NATIONS.slice(1));
}

