function toggleShortlist(id){state.shortlist=state.shortlist||[];const i=state.shortlist.indexOf(id);if(i>=0)state.shortlist.splice(i,1);else state.shortlist.push(id);saveState();render();toast(i>=0?'Dihapus dari shortlist.':'Masuk shortlist. Direksi mulai menghitung utang.');}
function compareShortlist(){const ps=(state.shortlist||[]).map(player).filter(Boolean).slice(0,4);if(ps.length<2)return toast('Shortlist minimal dua pemain buat dibandingkan, Einstein.');const attrs=['pace','shooting','passing','dribbling','tackling','stamina'];modal('Perbandingan Pemain',`<div class="table-wrap"><table><thead><tr><th>Atribut</th>${ps.map(p=>`<th>${p.name}</th>`).join('')}</tr></thead><tbody><tr><td>OVR</td>${ps.map(p=>`<td><strong>${p.scouted?p.ovr:'?'}</strong></td>`).join('')}</tr><tr><td>Potensi</td>${ps.map(p=>`<td>${potentialLabel(p)}</td>`).join('')}</tr><tr><td>Usia</td>${ps.map(p=>`<td>${p.age}</td>`).join('')}</tr><tr><td>Nilai</td>${ps.map(p=>`<td>${shortMoney(p.value)}</td>`).join('')}</tr>${attrs.map(k=>`<tr><td>${k}</td>${ps.map(p=>`<td>${p.scouted?p.attributes[k]:'?'}</td>`).join('')}</tr>`).join('')}</tbody></table></div>`);}
function filterTransferRows(){const q=($('#transfer-search')?.value||'').toLowerCase(),pos=$('#transfer-pos')?.value||'',league=$('#transfer-league')?.value||'',age=$('#transfer-age')?.value||'',only=$('#shortlist-only')?.checked;$$('#transfer-table [data-transfer-row]').forEach(r=>{const a=Number(r.dataset.age);const ageOk=!age||(age==='u21'&&a<=21)||(age==='22-27'&&a>=22&&a<=27)||(age==='28+'&&a>=28);const ok=(r.dataset.name||'').includes(q)&&(!pos||r.dataset.pos===pos)&&(!league||r.dataset.league===league)&&ageOk&&(!only||r.dataset.shortlisted==='true');r.classList.toggle('hidden',!ok);});}
function filterRows(sel,q,pos){q=(q||'').toLowerCase();$$(sel).forEach(r=>r.classList.toggle('hidden',!(r.dataset.name||'').includes(q)||(pos&&r.dataset.pos!==pos)));}
function swapLineup(a,b){const lists=[state.tactics.lineup,state.tactics.bench];let la,ia,lb,ib;lists.forEach(l=>{const i=l.indexOf(a);if(i>=0){la=l;ia=i;}const j=l.indexOf(b);if(j>=0){lb=l;ib=j;}});if(la&&lb){la[ia]=b;lb[ib]=a;saveState();render();}}
function deleteEntity(type,id){
  const labels={player:'pemain',club:'klub',staff:'staf'};modal(`Hapus ${labels[type]}?`,`<p>Data akan dihapus permanen dari autosave. Seperti karier pemain setelah tiga kartu merah, nggak enak tapi bisa.</p>`,`<button data-close-modal class="ghost">Batal</button><button id="confirm-delete" class="danger">Hapus</button>`);$('#confirm-delete').onclick=()=>{if(type==='player')state.players=state.players.filter(x=>x.id!==id);if(type==='staff')state.staffs=state.staffs.filter(x=>x.id!==id);if(type==='club'){if(id===state.manager.clubId)return toast('Jangan hapus klub yang sedang lu latih, dongo. Ganti klub dulu.');state.clubs=state.clubs.filter(x=>x.id!==id);state.players=state.players.filter(x=>x.clubId!==id);state.staffs=state.staffs.filter(x=>x.clubId!==id);Object.values(state.tables).forEach(t=>{const i=t.findIndex(x=>x.clubId===id);if(i>=0)t.splice(i,1);});}closeModal();saveState();render();};
}


