  if($('#preset-control'))$('#preset-control').onclick=()=>{Object.assign(state.tactics,{formation:'4-3-3',mentality:'Menyerang',tempo:'Normal',pressing:'Tinggi',width:'Lebar',line:'Tinggi',passingStyle:'Pendek',buildUp:'Dari Belakang',defensiveTransition:'Counter Press',attackingFocus:'Campuran',timeWasting:'Tidak'});saveState();render();};
  if($('#preset-counter'))$('#preset-counter').onclick=()=>{Object.assign(state.tactics,{formation:'4-2-3-1',mentality:'Defensif',tempo:'Cepat',pressing:'Sedang',width:'Normal',line:'Rendah',passingStyle:'Langsung',buildUp:'Langsung',defensiveTransition:'Regroup',attackingFocus:'Campuran',timeWasting:'Kadang'});saveState();render();};
